"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6609],{4631:e=>{e.exports=JSON.parse('{"tag":{"label":"migration","permalink":"/preview-docs/es/tutorial/tags/migration","allTagsPath":"/preview-docs/es/tutorial/tags","count":7,"items":[{"id":"migrate-files-volumes-copy","title":"Migrar archivos entre vol\xfamenes de Kubernetes con kubectl cp","description":"Copi\xe1 archivos almacenados en Persistent Volumes de Kubernetes de un cluster a otro usando kubectl cp, sin necesitar dumps de base de datos ni herramientas de snapshot.","permalink":"/preview-docs/es/tutorial/migrate-files-volumes-copy"},{"id":"migrate-external-s3","title":"Migrar un bucket S3 externo a SleakOps","description":"Copi\xe1 objetos desde un bucket S3 en una cuenta AWS externa a un bucket S3 administrado por SleakOps usando pol\xedticas de bucket cross-account y aws s3 sync.","permalink":"/preview-docs/es/tutorial/migrate-external-s3"},{"id":"migrate-rds-snapshot-between-accounts","title":"Migrar un snapshot de Amazon RDS entre cuentas","description":"Gu\xeda paso a paso para compartir y restaurar un snapshot de Amazon RDS entre cuentas de AWS, incluyendo escenarios con cifrado y cross-region.","permalink":"/preview-docs/es/tutorial/migrate-rds-snapshot-between-accounts"},{"id":"migrate-postgres-heroku-to-rds","title":"Migrar una base de datos PostgreSQL grande desde Heroku a RDS","description":"Migr\xe1 bases de datos PostgreSQL grandes (20 GB+) desde Heroku a Amazon RDS usando pgcopydb y un Job de SleakOps, con soporte para migraci\xf3n incremental posterior.","permalink":"/preview-docs/es/tutorial/migrate-postgres-heroku-to-rds"},{"id":"migrate-ebs-volumes","title":"Migrar vol\xfamenes EBS a una nueva cuenta de AWS","description":"Gu\xeda paso a paso para crear snapshots, compartir, copiar y recrear vol\xfamenes EBS desde una cuenta externa de AWS a una cuenta administrada por SleakOps.","permalink":"/preview-docs/es/tutorial/migrate-ebs-volumes"},{"id":"postgresql-dump-restore","title":"Restaurar un dump de PostgreSQL usando un Job de SleakOps","description":"Gu\xeda paso a paso para hacer dump y restaurar una base de datos PostgreSQL usando un Job temporal de SleakOps y una instancia RDS escalada.","permalink":"/preview-docs/es/tutorial/postgresql-dump-restore"},{"id":"dms-rds-migration","title":"Usar AWS DMS para sincronizar o migrar bases de datos RDS","description":"Gu\xeda paso a paso para migrar o sincronizar continuamente bases de datos RDS entre cuentas de AWS usando AWS Database Migration Service (DMS).","permalink":"/preview-docs/es/tutorial/dms-rds-migration"}],"unlisted":false}}')}}]);